import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.BbyMWZAR.js";const k=JSON.parse('{"title":"Context API 的使用场景？它能否替代 Redux 等状态管理？","description":"","frontmatter":{"title":"Context API 的使用场景？它能否替代 Redux 等状态管理？","difficulty":"medium","tags":["Context","Redux","状态管理"],"estimate":20},"headers":[],"relativePath":"domains/react/qa/06-context-api.md","filePath":"domains/react/qa/06-context-api.md","lastUpdated":1783504823000}'),n={name:"domains/react/qa/06-context-api.md"};function o(r,e,l,d,h,p){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="问答题-06-中级-context-api-的使用场景-它能否替代-redux-等状态管理" tabindex="-1">问答题 06（中级）：Context API 的使用场景？它能否替代 Redux 等状态管理？ <a class="header-anchor" href="#问答题-06-中级-context-api-的使用场景-它能否替代-redux-等状态管理" aria-label="Permalink to &quot;问答题 06（中级）：Context API 的使用场景？它能否替代 Redux 等状态管理？&quot;">​</a></h1><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><code>Context</code> 用于<strong>跨层级组件共享数据</strong>，避免逐层通过 props 传递（&quot;prop drilling&quot;）。典型场景：主题色、当前用户、语言（i18n）、路由信息、鉴权配置等<strong>变化不频繁</strong>的全局值。</p><p>用法三步：</p><div class="language-jsx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ThemeCtx</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> createContext</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;light&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ThemeCtx.Provider</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{theme}&gt;...&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ThemeCtx.Provider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> theme</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> useContext</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(ThemeCtx);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>Context ≠ 状态管理库</strong>：</p><ul><li>Context 只是<strong>依赖注入</strong>，没有内置的更新调度、选择器（selector）、中间件、时间旅行等能力。</li><li>Provider 的 <code>value</code> 变化时，<strong>所有消费该 Context 的组件都会重渲染</strong>，无法只订阅其中一部分字段，颗粒度粗。</li><li>对于高频更新、复杂派生、异步 action 的场景，Redux/Zustand/Jotai/Recoil 等更合适：它们提供订阅粒度控制、DevTools、可测试性。</li></ul><p>结论：小型应用或&quot;只读全局配置&quot;用 Context 够用；数据频繁变动、状态复杂时用专业状态管理。</p><h2 id="追问" tabindex="-1">追问 <a class="header-anchor" href="#追问" aria-label="Permalink to &quot;追问&quot;">​</a></h2><h3 id="追问-1-为什么-context-的-value-用对象字面量传递会导致性能问题" tabindex="-1">追问 1：为什么 Context 的 value 用对象字面量传递会导致性能问题？ <a class="header-anchor" href="#追问-1-为什么-context-的-value-用对象字面量传递会导致性能问题" aria-label="Permalink to &quot;追问 1：为什么 Context 的 value 用对象字面量传递会导致性能问题？&quot;">​</a></h3><p><strong>参考答案</strong>：每次父组件渲染都会创建<strong>新的对象引用</strong>，即使字段值相同，<code>Object.is</code> 比较也不相等，导致所有消费者都触发渲染。解决：用 <code>useMemo</code> 缓存对象，或把稳定不变的部分拆分成不同 Context。</p><h3 id="追问-2-如何避免-context-变化导致大范围重渲染" tabindex="-1">追问 2：如何避免 Context 变化导致大范围重渲染？ <a class="header-anchor" href="#追问-2-如何避免-context-变化导致大范围重渲染" aria-label="Permalink to &quot;追问 2：如何避免 Context 变化导致大范围重渲染？&quot;">​</a></h3><p><strong>参考答案</strong>：常见做法有：</p><ol><li>按更新频率<strong>拆分 Context</strong>（读少变少的放一个 Provider，高频变动的放另一个）。</li><li>把 setter 和 state 拆到两个 Context（消费 setter 的组件不会因 state 改变而渲染）。</li><li>使用 <code>use-context-selector</code> 等库实现选择器订阅。</li><li>用 <code>React.memo</code> 拦截无关子树。</li></ol><h3 id="追问-3-context-的默认值什么时候会被使用" tabindex="-1">追问 3：Context 的默认值什么时候会被使用？ <a class="header-anchor" href="#追问-3-context-的默认值什么时候会被使用" aria-label="Permalink to &quot;追问 3：Context 的默认值什么时候会被使用？&quot;">​</a></h3><p><strong>参考答案</strong>：仅当消费组件的上层<strong>没有匹配的 Provider</strong> 时，<code>createContext(defaultValue)</code> 的默认值才会生效。若外层存在 Provider，即使传入的 value 是 <code>undefined</code>，也会使用 Provider 的值，而不是默认值。默认值也常用于单元测试和 TS 类型推断。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/react/RESOURCES">React 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://react.dev/learn/passing-data-deeply-with-context" target="_blank" rel="noreferrer">React: Passing Data Deeply with Context</a>：Context 创建、Provider 与 <code>useContext</code></li><li><a href="https://react.dev/learn/scaling-up-with-reducer-and-context" target="_blank" rel="noreferrer">React: Scaling Up with Reducer and Context</a>：Context 与 reducer 组合传递 dispatch</li><li><a href="https://react.dev/learn/managing-state" target="_blank" rel="noreferrer">React: Managing State</a>：Context 适用边界与状态管理选型</li></ul>`,19)])])}const u=t(n,[["render",o]]);export{k as __pageData,u as default};
